query:
query Meetings {
  meetings(
    first: 2



  ) {
    items {
      duration
      endedAt
      id
      meetingType
      meetingUrl
      platformMeetingId
      rawTranscript
      source
      startedAt
      status
      summaryCreated
      topic
      transcriptCreatedAt
      transcriptId
      transcriptLanguage
    }
    pageInfo {
      hasNextPage
      endCursor
    }
  }
}
